+#[cfg(feature = "canvas")]
+#[allow(dead_code)]
+fn draw_canvas_circle_filled(painter: &mut Painter, cx: i32, cy: i32, radius: i32) {
+    let r = radius.max(1);
+    for y in (cy - r)..=(cy + r) {
+        for x in (cx - r)..=(cx + r) {
+            let dx = x - cx;
+            let dy = y - cy;
+            if dx * dx + dy * dy <= r * r {
+                painter.point(x, y);
+            }
+        }
+    }
+}
+
+#[cfg(feature = "canvas")]
+#[allow(dead_code)]
+fn draw_canvas_cross(painter: &mut Painter, cx: i32, cy: i32, radius: i32) {
+    let r = radius.max(1);
+    painter.line(cx - r, cy - r, cx + r, cy + r);
+    painter.line(cx - r, cy + r, cx + r, cy - r);
+}
